// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');

describe('F3 list history pro skill', function () {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function () {
    driver = await new Builder().forBrowser('chrome').usingServer('http://localhost:4444/wd/hub').build();
    vars = {};
  });
  afterEach(async function () {
    await driver.quit();
  });
  it('F3 list history pro skill', async function () {
    await driver.get('http://localhost:4200/home');
    await driver.manage().window().setRect({ width: 1936, height: 1056 });
    await driver.findElement(By.css('.ant-row:nth-child(4) .ant-card-body')).click();
    assert((await driver.findElement(By.css('.ant-typography:nth-child(1)')).getText()) == '専門スキル履歴一覧');
    assert(
      (await driver.findElement(By.css('.ant-form-item:nth-child(1) .ant-form-item-no-colon')).getText()) == '部署',
    );
    assert(
      (await driver.findElement(By.css('.ant-form-item:nth-child(2) .ant-form-item-no-colon')).getText()) == '状態',
    );
    await driver.findElement(By.css('#pro_skill_form > .ant-btn > span')).click();
    {
      const element = await driver.findElement(By.CSS_SELECTOR, 'body');
      await driver.actions({ bridge: true }).moveToElement(element, 0, 0).perform();
    }
    {
      const element = await driver.findElement(By.name('Search'));
      await driver.actions({ bridge: true }).moveToElement(element).perform();
    }
    {
      const element = await driver.findElement(By.CSS_SELECTOR, 'body');
      await driver.actions({ bridge: true }).moveToElement(element, 0, 0).perform();
    }
    assert((await driver.findElement(By.css('.ant-table-thead .ant-table-cell:nth-child(1)')).getText()) == '部署');
    assert(
      (await driver.findElement(By.css('.ant-table-thead .ant-table-cell:nth-child(2)')).getText()) == 'バージョン',
    );
    assert((await driver.findElement(By.css('.ant-table-thead .ant-table-cell:nth-child(3)')).getText()) == '状態');
    assert(
      (await driver.findElement(By.css('.ant-table-thead .ant-table-cell:nth-child(4)')).getText()) == '公開ステータス',
    );
    assert(
      (await driver.findElement(By.css('.ant-table-thead .ant-table-cell:nth-child(5)')).getText()) == '最終更新者',
    );
    assert(
      (await driver.findElement(By.css('.ant-table-thead .ant-table-cell:nth-child(6)')).getText()) == '最終更新日',
    );
    assert((await driver.findElement(By.css('.ant-table-thead .ant-table-cell:nth-child(7)')).getText()) == '公開日');
  });
});
